[```\newcommand{\amp}{&} \begin{aligned} \amp(2x+3)+(4x+5)\\ \amp=((2x+3)+4x)+5\amp\amp\text{using the associative property of addition}\\ \amp=(2x+(3+4x))+5\amp\amp\text{using the associative property of addition}\\ \amp=(2x+(4x+3))+5\amp\amp\text{using the commutative property of addition}\\ \amp=((2x+4x)+3)+5\amp\amp\text{using the associative property of addition}\\ \amp=(2x+4x)+(3+5)\amp\amp\text{using the associative property of addition}\\ \amp=(2+4)x+(3+5)\amp\amp\text{using the distributive property}\\ \amp=6x+8\amp\amp\text{using addition} \end{aligned} ```]
END_PGML_SOLUTION
