BEGIN_PGML_SOLUTION
[```\newcommand{\amp}{&} \begin{aligned} \amp(-5x+3)+(4x-7)\\ \amp=((-5x+3)+4x)+(-7)\amp\amp\text{using the associative property of addition}\\ \amp=(-5x+(3+4x))+(-7)\amp\amp\text{using the associative property of addition}\\ \amp=(-5x+(4x+3))+(-7)\amp\amp\text{using the commutative property of addition}\\ \amp=((-5x+4x)+3)+(-7)\amp\amp\text{using the associative property of addition}\\ \amp=(-5x+4x)+(3+(-7))\amp\amp\text{using the associative property of addition}\\ \amp=(-5+4)x+(3+(-7))\amp\amp\text{using the distributive property}\\ \amp=-1x+(-4)\amp\amp\text{using addition}\\ \amp=-x-4 \end{aligned} ```]
END_PGML_SOLUTION
